module.exports = {
  emit,
  consume,
  healthCheck,
  stats,

  // Day3-Gap2: 事件驱动便捷 emit 点
  emitInsightRequest,
  emitHealthRequest,
  emitAutoResponse,

  // 兼容新event-bus.js导出的常量
  EVENTS_FILE: bus._EVENTS_FILE,
  DATA_DIR: path.dirname(bus._EVENTS_FILE),
  DEDUPE_WINDOW_MS,

  // [Gap4] 兼容层：ack 透传给旧 bus（供 DTO/SEEF 等模块在迁移期间使用）
  ack: (consumerId, eventId) => bus.ack(consumerId, eventId),

  // 旧bus透传（渐进迁移用）
  legacy: bus,

  // 测试辅助
  _clearDedupeCache,
  _fingerprint,
  _matchWildcard,

  // 适配层标识
  _isAdapter: true,
};


// ═══════════════════════════════════════════════════════════
// 单元测试 — node bus-adapter.js 直接运行
